The E2E test should use manual setup (not fixtures) for fine-grained tab control:

```typescript
import { test, expect } from '@playwright/test';
import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';
import {
  cleanupTestConfigDir,
  copyE2eTestPlugin,
  launchExtensionContext,
  startMcpServer,
  startTestServer,
  writeTestConfig,
} from './fixtures.js';
import {
  openSidePanel,
